from prometheus_client import generate_latest, Counter, Histogram, Gauge, Summary, REGISTRY, PROCESS_COLLECTOR, PLATFORM_COLLECTOR

# Unregister default collectors to avoid conflicts or double registration issues if they were registered elsewhere
